t.script:
(function() {
    var banner = document.getElementById('upgrade-credit-banner');
    if (!banner) return;
    var key = 'dismissed_credit_' + banner.dataset.invoice;
    if (localStorage.getItem(key)) {
        banner.remove();
        return;
    }
    banner.style.display = '';
    document.getElementById('dismiss-upgrade-credit').addEventListener('click', function() {
        localStorage.setItem(key, '1');
        banner.remove();
        var card = document.querySelector('.info-card[style*="border-top"]');
        if (card) { card.style.borderTopLeftRadius = ''; card.style.borderTopRightRadius = ''; }
    });
})();

(function(){
    function bind(id){
        var cb = document.getElementById(id);
        if (!cb) return;
        cb.addEventListener('change', function(){
            var fd = new FormData();
            fd.append('csrf_token', document.querySelector('input[name="csrf_token"]').value);
            fd.append('kind', cb.dataset.kind);
            fd.append('enabled', cb.checked ? '1' : '0');
            fetch('/my/instances/' + cb.dataset.instanceId + '/billing/auto-renew', {
                method: 'POST',
                body: fd,
                credentials: 'same-origin',
            }).then(function(r){ return r.json(); })
              .then(function(data){
                  if (!data || !data.ok) {
                      cb.checked = !cb.checked;
                  }
              })
              .catch(function(){ cb.checked = !cb.checked; });
        });
    }
    bind('auto-renew-sub-toggle');
    bind('auto-renew-snap-toggle');
})();

div.script:
                                        (function() {
                                            var url = new URL(window.location);
                                            var result = url.searchParams.get('pkg_result');
                                            if (!result) return;
                                            // Remove param from URL without reload
                                            url.searchParams.delete('pkg_result');
                                            window.history.replaceState({}, '', url.toString());
                                            // Show banner
                                            var banner = document.getElementById('pkg-result-banner');
                                            var msgs = {
                                                success: ['alert-success', 'fa-check-circle', 'Packages installed successfully. Instance is restarting.'],
                                                partial: ['alert-warning', 'fa-exclamation-triangle', 'Some packages may have failed to install. Check logs for details.'],
                                                error: ['alert-danger', 'fa-times-circle', 'Package installation failed. Please check your package names and try again.'],
                                                invalid: ['alert-danger', 'fa-times-circle', 'One or more package specs are invalid. Use the form name[==version] (PEP 508). Options like --index-url and paths/URLs are not allowed.']
                                            };
                                            var m = msgs[result];
                                            if (!m) return;
                                            banner.className = 'alert-banner ' + m[0] + ' mb-3';
                                            banner.style.cssText = 'font-size:0.85rem;';
                                            banner.innerHTML = '
' + m[2] + '';
                                            // Auto-hide after 8 seconds
                                            setTimeout(function() { banner.style.display = 'none'; }, 8000);
                                        })();

section.script:
(function () {
    var instanceUrl = '/my/instances/?payment=success';

    // Monitor all navigation attempts and redirect /payment/status to instance page
    var observer = new MutationObserver(function () {
        if (window.location.pathname === '/payment/status') {
            window.location.replace(instanceUrl);
        }
    });
    observer.observe(document, { childList: true, subtree: true });

    // Intercept pushState
    var origPush = history.pushState;
    history.pushState = function () {
        if (arguments[2] && String(arguments[2]).indexOf('/payment/status') !== -1) {
            window.location.replace(instanceUrl);
            return;
        }
        return origPush.apply(this, arguments);
    };

    // Intercept replaceState
    var origReplace = history.replaceState;
    history.replaceState = function () {
        if (arguments[2] && String(arguments[2]).indexOf('/payment/status') !== -1) {
            window.location.replace(instanceUrl);
            return;
        }
        return origReplace.apply(this, arguments);
    };

    // Periodic check as fallback
    var checkInterval = setInterval(function () {
        if (window.location.pathname === '/payment/status') {
            clearInterval(checkInterval);
            window.location.replace(instanceUrl);
        }
    }, 500);

    // Stop checking after 60 seconds
    setTimeout(function () { clearInterval(checkInterval); }, 60000);
})();

(function () {
    var url = '/my/instances//backups?notice=Payment+received.+Daily+backups+are+now+active.';

    var observer = new MutationObserver(function () {
        if (window.location.pathname === '/payment/status') {
            window.location.replace(url);
        }
    });
    observer.observe(document, { childList: true, subtree: true });

    var origPush = history.pushState;
    history.pushState = function () {
        if (arguments[2] && String(arguments[2]).indexOf('/payment/status') !== -1) {
            window.location.replace(url);
            return;
        }
        return origPush.apply(this, arguments);
    };

    var origReplace = history.replaceState;
    history.replaceState = function () {
        if (arguments[2] && String(arguments[2]).indexOf('/payment/status') !== -1) {
            window.location.replace(url);
            return;
        }
        return origReplace.apply(this, arguments);
    };

    var checkInterval = setInterval(function () {
        if (window.location.pathname === '/payment/status') {
            clearInterval(checkInterval);
            window.location.replace(url);
        }
    }, 500);
    setTimeout(function () { clearInterval(checkInterval); }, 60000);
})();

t.script:
(function() {
    try {
        var u = new URL(window.location.href);
        var changed = false;
        ['notice', 'error'].forEach(function(p) {
            if (u.searchParams.has(p)) {
                u.searchParams.delete(p);
                changed = true;
            }
        });
        if (changed) {
            history.replaceState(null, '', u.toString());
        }
    } catch (e) { /* old browser, no-op */ }
})();

div.script:
(function() {
    var forms = document.querySelectorAll('.saas-ondemand-form');
    if (!forms.length) return;
    var locked = false;
    forms.forEach(function(form) {
        form.addEventListener('submit', function(ev) {
            if (locked) {
                ev.preventDefault();
                return false;
            }
            locked = true;
            // Mark the clicked button with a spinner,
            // disable every Backup Now on the page.
            var clicked = form.querySelector('.saas-ondemand-btn');
            document.querySelectorAll('.saas-ondemand-btn').forEach(function(b) {
                b.disabled = true;
                if (b === clicked) {
                    b.innerHTML = 'Starting…';
                }
            });
        });
    });
})();
